const express = require('express');
const jwt = require('jsonwebtoken');
const session = require('express-session');
const bodyParser = require('body-parser');
const { URL } = require('url');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(bodyParser.json());
app.use(session({
    secret: process.env.SESSION_SECRET || 'your_secret_key',
    resave: false,
    saveUninitialized: true,
    cookie: { secure: true } // Ensure this is true in production with HTTPS
}));

// OpenID Connect callback endpoint
app.post('/callback', (req, res) => {
    const idToken = req.body.id_token;

    // Validate the input
    if (typeof idToken !== 'string' || idToken.trim() === '') {
        return res.status(400).send('Invalid ID token');
    }

    // Decode the JWT ID token
    const decodedToken = jwt.decode(idToken);
    
    // Validate the decoded token
    if (!decodedToken || !decodedToken.sub) {
        return res.status(400).send('Invalid ID token');
    }

    // Create user session
    req.session.user = {
        id: decodedToken.sub,
        name: decodedToken.name,
        email: decodedToken.email
    };

    res.status(200).send('User session created');
});

// Start server
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});